def find_close_pairs(ntext, word1, word2, max_dist=40):
    inds1 = [m.start() for m in re.finditer(re.escape(word1), ntext)]
    inds2 = [m.start() for m in re.finditer(re.escape(word2), ntext)]
    for i in inds1:
        for j in inds2:
            if abs(i-j) <= max_dist:
                return True, (i,j)
    return False, None

